# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System.IO;

namespace FileServerApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder;
        private readonly IContentTypeProvider _contentTypeProvider;

        public FilesController(IWebHostEnvironment environment, IContentTypeProvider contentTypeProvider)
        {
            _uploadsFolder = Path.Combine(environment.ContentRootPath, "uploads");
            _contentTypeProvider = contentTypeProvider;
            
            if (!Directory.Exists(_uploadsFolder))
            {
                Directory.CreateDirectory(_uploadsFolder);
            }
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename cannot be empty");
            }

            try
            {
                string requestedPath = Path.Combine(_uploadsFolder, filename);
                string canonicalRequestedPath = Path.GetFullPath(requestedPath);
                string canonicalBasePath = Path.GetFullPath(_uploadsFolder);

                if (!canonicalRequestedPath.StartsWith(canonicalBasePath + Path.DirectorySeparatorChar) &&
                    !canonicalRequestedPath.Equals(canonicalBasePath))
                {
                    return BadRequest("Invalid file path");
                }

                if (!System.IO.File.Exists(canonicalRequestedPath))
                {
                    return NotFound("File not found");
                }

                if (!_contentTypeProvider.TryGetContentType(canonicalRequestedPath, out string contentType))
                {
                    contentType = "application/octet-stream";
                }

                var fileStream = new FileStream(canonicalRequestedPath, FileMode.Open, FileAccess.Read, FileShare.Read);
                
                return File(fileStream, contentType, Path.GetFileName(canonicalRequestedPath));
            }
            catch (Exception ex)
            {
                return StatusCode(500, "Error retrieving file");
            }
        }

        [HttpGet("download/{filename}")]
        public IActionResult DownloadFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename cannot be empty");
            }

            try
            {
                string requestedPath = Path.Combine(_uploadsFolder, filename);
                string canonicalRequestedPath = Path.GetFullPath(requestedPath);
                string canonicalBasePath = Path.GetFullPath(_uploadsFolder);

                if (!canonicalRequestedPath.StartsWith(canonicalBasePath + Path.DirectorySeparatorChar) &&
                    !canonicalRequestedPath.Equals(canonicalBasePath))
                {
                    return BadRequest("Invalid file path");
                }

                if (!System.IO.File.Exists(canonicalRequestedPath))
                {
                    return NotFound("File not found");
                }

                if (!_contentTypeProvider.TryGetContentType(canonicalRequestedPath, out string contentType))
                {
                    contentType = "application/octet-stream";
                }

                var fileStream = new FileStream(canonicalRequestedPath, FileMode.Open, FileAccess.Read, FileShare.Read);
                
                return File(fileStream, contentType, Path.GetFileName(canonicalRequestedPath), enableRangeProcessing: true);
            }
            catch (Exception ex)
            {
                return StatusCode(500, "Error downloading file");
            }
        }
    }
}